#!/usr/bin/env python3
"""
apply_v322r_leveraged_scalp_exclusion.py  (SentCom v322r)

Idempotent applier for the 2026-06-12 EXT_SL autopsy fix: leveraged-instrument
scalp exclusion (the ARMG -3.93R gap-through class).

WHAT IT DOES
  services/etf_classifier.py
    - Adds ARMG + AAPB/FBL/NVDX/NVDQ/TSLT/BRKU to SINGLE_STOCK_LEVERAGED.
    - Adds LEVERAGED_NAME_RE + name_looks_leveraged() + is_known_leveraged()
      (IB longName/stockType heuristic, the safety net for NEW launches).
  services/ib_direct_service.py
    - Adds get_contract_profile(symbol) -> {long_name, stock_type}.
  services/enhanced_scanner.py
    - __init__: SCALP_BLOCK_LEVERAGED (default true) +
      SCALP_LEVERAGED_ALLOW (default TQQQ,SQQQ,SOXL,SOXS) + probe cache.
    - New _is_leveraged_instrument(): static classifier -> IB longName probe,
      fail-OPEN, in-process cached.
    - _passes_universal_liquidity_gate: blocks leveraged ETPs for
      scalp/intraday styles BEFORE the known-liquid bypass (UVXY-class
      symbols would otherwise skip the gate entirely). Drops land in
      trade_drops gate=scalp_leveraged_exclusion + a scanner thought.
  NEW tests/test_v322r_leveraged_scalp_exclusion.py (22 tests)
  NEW scripts/diag_eod_flatten_escape.py (ACMR 65-hour escape probe, read-only)

SAFETY
  - Idempotent: no-op when the v322r markers already exist.
  - Refuses to write unless ALL hunks match exactly once.
  - Timestamped .bak + py_compile validation with auto-restore.
  - Hunks are base64-embedded => byte-exact.

USAGE
  cd ~/Trading-and-Analysis-Platform
  .venv/bin/python apply_v322r_leveraged_scalp_exclusion.py            # apply
  .venv/bin/python apply_v322r_leveraged_scalp_exclusion.py --dry-run  # check only

AFTER APPLYING (CRITICAL — StartTrading.bat runs `git checkout -- .`):
  .venv/bin/python -m pytest backend/tests/test_v322r_leveraged_scalp_exclusion.py backend/tests/test_v322m_scalp_liquidity.py -q
  git add -A && git commit -m "v322r: leveraged-instrument scalp exclusion + EOD escape probe" && git push origin main
  # THEN restart the backend.
"""
import argparse
import base64
import os
import py_compile
import shutil
import sys
import time

MARKER = "v322r"

HUNKS = [
    ('services/etf_classifier.py', 'services/etf_classifier.py hunk 1 (lines ~46-51)',
     'ICAgICJNRVRVIiwgIk1FVEQiLCAiQU1aVSIsICJBTVpEIiwKICAgICJBVkdYIiwgIkFWR0QiLCAiU01DWCIsICJTTUNaIiwgIkNPSVciLCAiQ09JRyIsCiAgICAiQkFCWCIsICJQQUxVIiwgIkhPT1giLCAiUkJMVSIsCn0KCkxFVkVSQUdFRF9JTlZFUlNFOiBTZXRbc3RyXSA9IFNJTkdMRV9TVE9DS19MRVZFUkFHRUQgfCBGT0NVU19FWEVNUFQgfCB7Cg==',
     ''),
    ('services/etf_classifier.py', 'services/etf_classifier.py hunk 2 (lines ~177-179)',
     'ICAgIGlmIHN5bSBpbiBTSU5HTEVfU1RPQ0tfTEVWRVJBR0VEOgogICAgICAgIHJldHVybiBGYWxzZQogICAgcmV0dXJuIF9DTEFTU19NQVAuZ2V0KHN5bSkgbm90IGluIEwxX0VYQ0xVREVEX0NMQVNTRVMK',
     ''),
    ('services/ib_direct_service.py', 'services/ib_direct_service.py hunk 1 (lines ~741-746)',
     'ICAgICAgICBleGNlcHQgRXhjZXB0aW9uIGFzIGV4YzoKICAgICAgICAgICAgbG9nZ2VyLmRlYnVnKAogICAgICAgICAgICAgICAgIlt2MTkuMzQuMTc2IGdldF9jb250cmFjdF9pbmR1c3RyeV0gJXMgbG9va3VwIGZhaWxlZDogJXMiLAogICAgICAgICAgICAgICAgc3ltYm9sLCBleGMsCiAgICAgICAgICAgICkKICAgICAgICAgICAgcmV0dXJuIE5vbmUK',
     ''),
    ('services/enhanced_scanner.py', 'services/enhanced_scanner.py hunk 1 (lines ~892-897)',
     '',
     ''),
    ('services/enhanced_scanner.py', 'services/enhanced_scanner.py hunk 2 (lines ~1649-1654)',
     '',
     ''),
    ('services/enhanced_scanner.py', 'services/enhanced_scanner.py hunk 3 (lines ~1697-1702)',
     '',
     ''),
]

NEW_FILES = [
    ('tests/test_v322r_leveraged_scalp_exclusion.py',
     ''),
    ('scripts/diag_eod_flatten_escape.py',
     ''),
]


def _d(s):
    return base64.b64decode(s).decode("utf-8")


def log(m):
    print(f"[v322r-applier] {m}", flush=True)


def find_repo(explicit):
    if explicit:
        return explicit
    here = os.path.abspath(os.path.dirname(__file__))
    for base in (here, os.getcwd(), os.path.expanduser("~/Trading-and-Analysis-Platform")):
        cur = base
        for _ in range(6):
            if os.path.isfile(os.path.join(cur, "backend", "services", "enhanced_scanner.py")):
                return cur
            parent = os.path.dirname(cur)
            if parent == cur:
                break
            cur = parent
    return None


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--repo", default=None)
    ap.add_argument("--dry-run", action="store_true")
    args = ap.parse_args()
    repo = find_repo(args.repo)
    if not repo:
        log("FATAL: repo not found (use --repo)")
        sys.exit(1)
    log(f"repo: {repo}")

    # group hunks by file
    by_file = {}
    for rel, label, old_b64, new_b64 in HUNKS:
        by_file.setdefault(rel, []).append((label, _d(old_b64), _d(new_b64)))

    plans = []
    for rel, hunks in by_file.items():
        path = os.path.join(repo, "backend", rel)
        if not os.path.isfile(path):
            log(f"FATAL: missing {path}")
            sys.exit(1)
        src = open(path, encoding="utf-8").read()
        if MARKER in src:
            log(f"SKIP (already applied): {rel}")
            continue
        new_src = src
        for label, old, new in hunks:
            cnt = new_src.count(old)
            if cnt != 1:
                log(f"FATAL: {label} matched {cnt}x (expected 1). File drifted — do NOT apply.")
                sys.exit(1)
            new_src = new_src.replace(old, new, 1)
            log(f"  ok: {label}")
        plans.append((path, new_src))

    new_file_plans = []
    for rel, b64 in NEW_FILES:
        path = os.path.join(repo, "backend", rel)
        content = _d(b64)
        if os.path.isfile(path) and open(path, encoding="utf-8").read() == content:
            log(f"SKIP new file (identical): {rel}")
            continue
        new_file_plans.append((path, content))
        log(f"  will create: {rel}")

    if args.dry_run:
        log(f"DRY-RUN OK — {len(plans)} file(s) to patch, {len(new_file_plans)} to create.")
        return

    stamp = time.strftime("%Y%m%d_%H%M%S")
    backups = []
    for path, new_src in plans:
        bak = f"{path}.{stamp}.bak"
        shutil.copy2(path, bak)
        backups.append((path, bak))
        with open(path, "w", encoding="utf-8") as f:
            f.write(new_src)
        log(f"patched: {path} (backup: {os.path.basename(bak)})")
    for path, content in new_file_plans:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
        log(f"created: {path}")

    # validate
    failed = False
    for path, _ in plans + [(p, None) for p, _ in new_file_plans]:
        if not path.endswith(".py"):
            continue
        try:
            py_compile.compile(path, doraise=True)
        except Exception as e:
            log(f"COMPILE FAIL: {path}: {e}")
            failed = True
    if failed:
        for path, bak in backups:
            shutil.copy2(bak, path)
        log("RESTORED all backups. Nothing applied.")
        sys.exit(1)

    log("SUCCESS. Now run the tests, then git add/commit/push BEFORE restarting:")
    log("  .venv/bin/python -m pytest backend/tests/test_v322r_leveraged_scalp_exclusion.py -q")
    log('  git add -A && git commit -m "v322r: leveraged scalp exclusion + EOD escape probe" && git push origin main')


if __name__ == "__main__":
    main()
